#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,k; scanf("%d %d",&n,&k);
        if(k==n-1){
            printf("-1\n");
            continue;
        }
        int *a = (int*)malloc((n+1)*sizeof(int));
        int i;
        for(i=1;i<=k;i++) a[i]=i;
        int m=n-k;
        if(m>0){
            for(i=1;i<m;i++) a[k+i]=k+i+1;
            a[n]=k+1;
        }
        for(i=1;i<=n;i++){
            if(i>1) printf(" ");
            printf("%d",a[i]);
        }
        printf("\n");
        free(a);
    }
    return 0;
}

