import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); k = int(next(it))
        if k == n - 1:
            out_lines.append('-1')
            continue
        ans = [0] * (n + 1)
        for i in range(1, k + 1):
            ans[i] = i
        m = n - k
        if m > 0:
            for i in range(1, m):
                ans[k + i] = k + i + 1
            ans[n] = k + 1
        out_lines.append(' '.join(str(ans[i]) for i in range(1, n + 1)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

